#include <ranges>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3, 4, 5};
    auto doubled = v | std::views::transform([](int x) { return x * 2; });
    for (int x : doubled) std::cout << x << ' ';
    // المخرجات: 2 4 6 8 10
}

#include <ranges>
#include <vector>
#include <string>
#include <iostream>

struct Student { std::string name; int score; };

int main() {
    std::vector<Student> students = {{"Ali", 90}, {"Sara", 85}, {"Omar", 95}};
    auto names = students | std::views::transform([](const Student& s) { return s.name; });
    for (const auto& n : names) std::cout << n << ' ';
    // المخرجات: Ali Sara Omar
}

#include <ranges>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3, 4, 5, 6};
    auto result = v
        | std::views::filter([](int x) { return x % 2 == 0; })
        | std::views::transform([](int x) { return x * x; });
    for (int x : result) std::cout << x << ' ';
    // المخرجات: 4 16 36 (الأزواج مربّعة)
}

