#include <ranges>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, -1, 3, 4};

    auto tw = v | std::views::take_while([](int x) { return x > 0; });
    for (int x : tw) std::cout << x << ' ';
    // المخرجات: 1 2 (يتوقف عند -1)

    auto fi = v | std::views::filter([](int x) { return x > 0; });
    for (int x : fi) std::cout << x << ' ';
    // المخرجات: 1 2 3 4 (كل الموجبة)
}

#include <ranges>
