#include <ranges>
#include <string>
#include <vector>
#include <iostream>

int main() {
    std::vector<std::string> lines = {"a b c", "d e", "f"};
    auto words = lines
        | std::views::transform([](const std::string& s) {
            return std::views::split(s, ' ');
        })
        | std::views::join;
    for (auto word : words) {
        std::string w(word.begin(), word.end());
        std::cout << w << ' ';
    }
    // المخرجات: a b c d e f
}

