#include <algorithm>
#include <vector>
#include <iterator>
#include <iostream>

int main() {
    std::vector<int> src = {1, 2, 3};
    std::vector<int> dst;
    std::ranges::copy(src, std::back_inserter(dst));
    for (int x : dst) std::cout << x << ' ';
    // المخرجات: 1 2 3
}

#include <algorithm>
#include <vector>
#include <iterator>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3};
    std::vector<int> dst;
    std::ranges::transform(v, std::back_inserter(dst), [](int x) { return x * 2; });
    for (int x : dst) std::cout << x << ' ';
    // المخرجات: 2 4 6
}
